-- seeds.sql — real data from Virgo_Operations_Hub_MRP.xlsx
-- Run AFTER schema.sql. Safe to rerun (ON CONFLICT DO NOTHING).

-- ── CUSTOMERS (50 Shopify contacts) ──
on conflict (external_customer_id) do nothing;

-- ── SALES ORDERS (50 from Shopify) ──
on conflict (so_number) do nothing;

-- ── SHIPMENTS (76 shipping records) ──
on conflict (shipment_id) do nothing;

-- ── SERIAL NUMBERS (54 serials linking product → customer → shipment) ──
on conflict (serial_number) do nothing;

-- ── MAKE ORDERS (4 production runs) ──
on conflict (mo_number) do nothing;

-- ── PURCHASE ORDERS (5 open/recent POs) ──
on conflict (po_number) do nothing;
